class Solution:
    def maxWidthRamp(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            for j in range(n - 1, i, -1):
                if nums[j] >= nums[i]:
                    if j - i > best:
                        best = j - i
                    break
        return best

